// RelationshipType distinguishes HasMany from HasOne.
type RelationshipType int

const (
	RelHasMany RelationshipType = iota
	RelHasOne
)

// Relationship records a nested child table declared via HasMany/HasOne.
type Relationship struct {
	Type         RelationshipType
	Name         string // child table name (e.g., "posts")
	ChildTable   *Table // child schema definition
	ParentTable  string // parent table name (set during CreateTable)
	IsCollection bool   // .Collection() — separate collection for doc stores
	IsTopLevel   bool   // .TopLevelModel() — generate at models/ not models/parent/
}

func (r *Relationship) Collection() *Relationship {
	r.IsCollection = true
	return r
}

func (r *Relationship) TopLevelModel() *Relationship {
	r.IsTopLevel = true
	return r
}

// Table collects column definitions for a database table.
type Table struct {
	Name          string
	Connection    string // database connection name ("" = default)
	Columns       []*Column
	Relationships []*Relationship
	IsImmutable   bool // set by Immutable() — versioned, (id, version_id) composite PK
	IsAppendOnly  bool // set by AppendOnly() — insert-only, single id PK, no updates/deletes
	HasSoftDelete bool // set by SoftDeletes() — adds deleted_at nullable column
}

func (t *Table) addColumn(name string, colType ColumnType) *Column {
	if name == "" {
		panic("pickle: column name must not be empty")
	}
	c := &Column{
		Name: name,
		Type: colType,
	}
	t.Columns = append(t.Columns, c)
	return c
}

func (t *Table) UUID(name string) *Column {
	return t.addColumn(name, UUID)
}

func (t *Table) String(name string, length ...int) *Column {
	c := t.addColumn(name, String)
	if len(length) > 0 {
		if length[0] < 1 {
			panic("pickle: string length must be >= 1")
		}
		c.Length = length[0]
	} else {
		c.Length = 255
	}
	return c
}

func (t *Table) Text(name string) *Column {
	return t.addColumn(name, Text)
}

func (t *Table) Integer(name string) *Column {
	return t.addColumn(name, Integer)
}

func (t *Table) BigInteger(name string) *Column {
	return t.addColumn(name, BigInteger)
}

func (t *Table) Decimal(name string, precision, scale int) *Column {
	if precision < 1 {
		panic("pickle: decimal precision must be >= 1")
	}
	if scale < 0 {
		panic("pickle: decimal scale must be >= 0")
	}
	if scale > precision {
		panic("pickle: decimal scale must not exceed precision")
	}
	c := t.addColumn(name, Decimal)
	c.Precision = precision
	c.Scale = scale
	return c
}

func (t *Table) Boolean(name string) *Column {
	return t.addColumn(name, Boolean)
}

func (t *Table) Timestamp(name string) *Column {
	return t.addColumn(name, Timestamp)
}

func (t *Table) JSONB(name string) *Column {
	return t.addColumn(name, JSONB)
}

func (t *Table) Date(name string) *Column {
	return t.addColumn(name, Date)
}

func (t *Table) Time(name string) *Column {
	return t.addColumn(name, Time)
}

func (t *Table) Binary(name string) *Column {
	return t.addColumn(name, Binary)
}

// Float adds a single-precision floating-point column (SQL REAL / FLOAT).
// In almost all cases you should use Decimal(name, precision, scale) instead.
func (t *Table) Float(name string) *Column {
	return t.addColumn(name, Float)
}

// Double adds a double-precision floating-point column (SQL DOUBLE PRECISION).
// In almost all cases you should use Decimal(name, precision, scale) instead.
func (t *Table) Double(name string) *Column {
	return t.addColumn(name, Double)
}

// HasMany declares a one-to-many relationship. The child table gets an
// auto-injected FK column pointing back to this table's primary key.
func (t *Table) HasMany(name string, fn func(*Table)) *Relationship {
	child := &Table{Name: name}
	fn(child)
	r := &Relationship{
		Type:        RelHasMany,
		Name:        name,
		ChildTable:  child,
		ParentTable: t.Name,
	}
	t.Relationships = append(t.Relationships, r)
	return r
}

// HasOne declares a one-to-one relationship. The child table gets an
// auto-injected unique FK column pointing back to this table's primary key.
func (t *Table) HasOne(name string, fn func(*Table)) *Relationship {
	child := &Table{Name: name}
	fn(child)
	r := &Relationship{
		Type:        RelHasOne,
		Name:        name,
		ChildTable:  child,
		ParentTable: t.Name,
	}
	t.Relationships = append(t.Relationships, r)
	return r
}

// Timestamps adds created_at and updated_at columns with NOW() defaults.
// Panics if called on an immutable or append-only table — those derive
// timestamps from UUID v7.
func (t *Table) Timestamps() {
	if t.IsImmutable {
		panic("pickle: Timestamps() must not be called on immutable table \"" + t.Name + "\" — CreatedAt and UpdatedAt are derived from UUID v7 timestamps in id and version_id")
	}
	if t.IsAppendOnly {
		panic("pickle: Timestamps() must not be called on append-only table \"" + t.Name + "\" — CreatedAt is derived from the UUID v7 timestamp in id")
	}
	t.addColumn("created_at", Timestamp).NotNull().Default("NOW()")
	t.addColumn("updated_at", Timestamp).NotNull().Default("NOW()")
}

// Immutable marks this table as append-only. Pickle injects id and version_id
// as a composite primary key and generates insert-on-update query behaviour.
// Do not call Timestamps() on an immutable table — created_at and updated_at
// are derived from the UUID v7 timestamps embedded in id and version_id.
func (t *Table) Immutable() {
	t.IsImmutable = true
	id := &Column{
		Name:         "id",
		Type:         UUID,
		IsPrimaryKey: true,
	}
	versionID := &Column{
		Name:         "version_id",
		Type:         UUID,
		IsPrimaryKey: true,
	}
	rowHash := &Column{
		Name: "row_hash",
		Type: Binary,
	}
	prevHash := &Column{
		Name: "prev_hash",
		Type: Binary,
	}
	t.Columns = append([]*Column{id, versionID, rowHash, prevHash}, t.Columns...)
}

// AppendOnly marks this table as insert-only. Pickle injects a single id
// primary key. The generated query type has no Update or Delete methods.
// CreatedAt is derived from the UUID v7 timestamp in id.
// Use this for financial ledgers, event logs, and audit journals where
// records must never be modified after creation.
func (t *Table) AppendOnly() {
	if t.IsImmutable {
		panic("pickle: AppendOnly() and Immutable() are mutually exclusive on table \"" + t.Name + "\"")
	}
	t.IsAppendOnly = true
	id := &Column{
		Name:         "id",
		Type:         UUID,
		IsPrimaryKey: true,
	}
	rowHash := &Column{
		Name: "row_hash",
		Type: Binary,
	}
	prevHash := &Column{
		Name: "prev_hash",
		Type: Binary,
	}
	t.Columns = append([]*Column{id, rowHash, prevHash}, t.Columns...)
}

// SoftDeletes adds a nullable deleted_at timestamp column.
// On an immutable table, Delete() inserts a new version with deleted_at set.
// On a mutable table, Delete() issues a standard soft-delete UPDATE.
// Panics on append-only tables — append-only records cannot be deleted.
func (t *Table) SoftDeletes() {
	if t.IsAppendOnly {
		panic("pickle: SoftDeletes() must not be called on append-only table \"" + t.Name + "\" — append-only records cannot be deleted")
	}
	t.HasSoftDelete = true
	t.addColumn("deleted_at", Timestamp).Nullable()
}

// ColumnType represents the data type of a database column.
type ColumnType int

const (
	UUID ColumnType = iota
	String
	Text
	Integer
	BigInteger
	Decimal
	Boolean
	Timestamp
	JSONB
	Date
	Time
	Binary
	Float
	Double
)

var columnTypeNames = [...]string{
	UUID:       "uuid",
	String:     "string",
	Text:       "text",
	Integer:    "integer",
	BigInteger: "bigint",
	Decimal:    "decimal",
	Boolean:    "boolean",
	Timestamp:  "timestamp",
	JSONB:      "jsonb",
	Date:       "date",
	Time:       "time",
	Binary:     "binary",
	Float:      "float",
	Double:     "double",
}

func (t ColumnType) String() string {
	if int(t) < len(columnTypeNames) {
		if name := columnTypeNames[t]; name != "" {
			return name
		}
	}
	return "unknown"
}

// View represents a database view definition.
type View struct {
	Name         string
	Sources      []ViewSource
	Columns      []*ViewColumn
	GroupByCols  []string
}

// ViewSource represents a table referenced by a view (FROM or JOIN).
type ViewSource struct {
	Table         string
	Alias         string
	JoinType      string // "" for FROM, "JOIN", "LEFT JOIN"
	JoinCondition string
}

// ViewColumn represents a column in a view's SELECT list.
type ViewColumn struct {
	Column                       // embedded — carries Name, Type, Precision, Scale, IsNullable
	SourceAlias  string          // e.g. "t" from "t.id"
	SourceColumn string          // e.g. "id" from "t.id"
	OutputAlias  string          // optional alias for the output column name
	RawExpr      string          // raw SQL expression (for SelectRaw)
}

// OutputName returns the column name as it appears in the view's output.
func (vc *ViewColumn) OutputName() string {
	if vc.OutputAlias != "" {
		return vc.OutputAlias
	}
	if vc.SourceColumn != "" {
		return vc.SourceColumn
	}
	return vc.Name
}

// From sets the primary source table for the view.
func (v *View) From(table, alias string) {
	if table == "" || alias == "" {
		panic("pickle: View.From requires non-empty table and alias")
	}
	v.Sources = append(v.Sources, ViewSource{
		Table: table,
		Alias: alias,
	})
}

// Join adds an INNER JOIN to the view.
func (v *View) Join(table, alias, on string) {
	if table == "" || alias == "" || on == "" {
		panic("pickle: View.Join requires non-empty table, alias, and ON condition")
	}
	v.Sources = append(v.Sources, ViewSource{
		Table:         table,
		Alias:         alias,
		JoinType:      "JOIN",
		JoinCondition: on,
	})
}

// LeftJoin adds a LEFT JOIN to the view.
func (v *View) LeftJoin(table, alias, on string) {
	if table == "" || alias == "" || on == "" {
		panic("pickle: View.LeftJoin requires non-empty table, alias, and ON condition")
	}
	v.Sources = append(v.Sources, ViewSource{
		Table:         table,
		Alias:         alias,
		JoinType:      "LEFT JOIN",
		JoinCondition: on,
	})
}

// Column adds a column reference from a source table.
// ref is "alias.column" (e.g. "t.id"). An optional second argument aliases the output.
func (v *View) Column(ref string, alias ...string) {
	srcAlias, srcCol := parseColumnRef(ref)
	vc := &ViewColumn{
		SourceAlias:  srcAlias,
		SourceColumn: srcCol,
	}
	// Default the Name to the source column; overridden by alias if provided
	vc.Name = srcCol
	if len(alias) > 0 {
		vc.OutputAlias = alias[0]
		vc.Name = alias[0]
	}
	v.Columns = append(v.Columns, vc)
}

// SelectRaw adds a computed column with a raw SQL expression.
// Returns the ViewColumn so the caller can chain type builder methods.
func (v *View) SelectRaw(name, expr string) *ViewColumn {
	if name == "" || expr == "" {
		panic("pickle: SelectRaw requires non-empty name and expression")
	}
	vc := &ViewColumn{
		RawExpr: expr,
	}
	vc.Name = name
	v.Columns = append(v.Columns, vc)
	return vc
}

// GroupBy sets the GROUP BY columns.
func (v *View) GroupBy(columns ...string) {
	v.GroupByCols = columns
}

// --- Type builder methods on ViewColumn (for SelectRaw) ---

func (vc *ViewColumn) BigInteger() *ViewColumn {
	vc.Type = BigInteger
	return vc
}

func (vc *ViewColumn) IntegerType() *ViewColumn {
	vc.Type = Integer
	return vc
}

func (vc *ViewColumn) Decimal(precision, scale int) *ViewColumn {
	vc.Type = Decimal
	vc.Precision = precision
	vc.Scale = scale
	return vc
}

func (vc *ViewColumn) StringType(length ...int) *ViewColumn {
	vc.Type = String
	if len(length) > 0 {
		vc.Length = length[0]
	} else {
		vc.Length = 255
	}
	return vc
}

func (vc *ViewColumn) TextType() *ViewColumn {
	vc.Type = Text
	return vc
}

func (vc *ViewColumn) BooleanType() *ViewColumn {
	vc.Type = Boolean
	return vc
}

func (vc *ViewColumn) TimestampType() *ViewColumn {
	vc.Type = Timestamp
	return vc
}

func (vc *ViewColumn) UUIDType() *ViewColumn {
	vc.Type = UUID
	return vc
}

func (vc *ViewColumn) JSONBType() *ViewColumn {
	vc.Type = JSONB
	return vc
}

// parseColumnRef splits "alias.column" into parts.
func parseColumnRef(ref string) (alias, column string) {
	for i := 0; i < len(ref); i++ {
		if ref[i] == '.' {
			return ref[:i], ref[i+1:]
		}
	}
	panic("pickle: column reference must be in 'alias.column' format, got: " + ref)
}

